class Solution(object):
    def hasValidPath(self, grid):
        m, n = len(grid), len(grid[0])
        directions = {1: [(0,1), (0,-1)], 2: [(1,0), (-1,0)], 3: [(0,-1), (1,0)], 4: [(0,1), (1,0)], 5: [(0,-1), (-1,0)], 6: [(0,1), (-1,0)]}
        visited = set()
        def dfs(r, c, from_dir):
            if r < 0 or r >= m or c < 0 or c >= n or (r,c) in visited:
                return False
            if r == m - 1 and c == n - 1:
                return True
            visited.add((r, c))
            street = grid[r][c]
            for dr, dc in directions[street]:
                if from_dir and (dr, dc) == from_dir:
                    continue
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    next_street = grid[nr][nc]
                    if (-dr, -dc) in directions[next_street]:
                        if dfs(nr, nc, (dr, dc)):
                            return True
            return False
        return dfs(0, 0, None)
